parameters.content:
/**
 * Notification models and types for the event-driven notification system.
 *
 * ARCHITECTURAL DECISION: Event-Driven Notification System
 * =========================================================
 *
 * Pattern chosen: EVENT-DRIVEN (via EventBus)
 *
 * Why event-driven over direct service calls:
 * 1. The codebase already uses EventBus for inter-service communication.
 *    CLAUDE.md states: "Events are preferred over direct cross-service calls."
 * 2. Loose coupling — services emit domain events without knowing who consumes them.
 *    Adding a new notification channel (SMS, push, webhook) requires zero changes
 *    to the services that emit events.
 * 3. Multiple listeners can independently react to the same event
 *    (e.g., order:created triggers both email confirmation AND in-app notification).
 * 4. The EventBus provides an event log for debugging and replay capability.
 *
 * Constraints this imposes:
 * - ALL notifications MUST originate from EventBus events. Never call adapters directly
 *   from business logic. The flow is:
 *     Service emits domain event -> EventBus -> NotificationService -> Adapter
 * - ALL adapters MUST implement the NotificationAdapter interface.
 * - ALL new notification channels MUST be registered with the NotificationService
 *   via registerAdapter() before they can receive notifications.
 * - Adapters MUST NOT throw — they return NotificationResult with success/failure.
 * - The NotificationService is the ONLY service that dispatches to adapters.
 *   Other services must emit events, not send notifications directly.
 *
 * How to extend (for other developers):
 * - To add a new channel: implement NotificationAdapter, register it with NotificationService.
 * - To handle a new event: add an event handler in NotificationService.registerEventHandlers().
 * - To add notification preferences: extend NotificationPayload.metadata or create a
 *   NotificationPreferences model.
 */

/**
 * Supported notification delivery channels.
 * Add new channels here when implementing new adapters.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook' | 'sms';

/**
 * Notification delivery status lifecycle.
 * - pending: created, not yet dispatched to adapter
 * - sent: adapter confirmed delivery
 * - failed: adapter reported a failure
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Priority levels for notification delivery.
 * Adapters may use this to determine delivery urgency.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed through the notification pipeline.
 * Created by NotificationService from domain events, sent to adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification identifier */
  id: string;
  /** Delivery channel for this notification */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject or title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery priority */
  priority: NotificationPriority;
  /** Optional key-value metadata for adapter-specific data */
  metadata?: Record<string, string>;
  /** When this notification was created */
  createdAt: Date;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 * Adapters MUST return this (never throw). Use success=false for errors.
 */
export interface NotificationResult {
  /** Whether delivery succeeded */
  success: boolean;
  /** The notification ID that was sent */
  notificationId: string;
  /** The channel used for delivery */
  channel: NotificationChannel;
  /** Error message if success is false */
  error?: string;
  /** Timestamp of successful delivery */
  sentAt?: Date;
}

/**
 * A stored notification record with full status tracking.
 * Persisted by the NotificationService for auditing and querying.
 */
export interface Notification {
  /** Unique notification identifier */
  id: string;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject or title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery priority */
  priority: NotificationPriority;
  /** Current delivery status */
  status: NotificationStatus;
  /** Optional key-value metadata */
  metadata?: Record<string, string>;
  /** Error message if delivery failed */
  error?: string;
  /** When this notification was created */
  createdAt: Date;
  /** When this notification was successfully delivered */
  sentAt?: Date;
}

/**
 * Input for creating a notification through the NotificationService.
 * Omits id, status, and timestamps which are set by the service.
 */
export interface CreateNotificationInput {
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject or title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery priority (defaults to 'normal' if omitted) */
  priority?: NotificationPriority;
  /** Optional key-value metadata */
  metadata?: Record<string, string>;
}

/**
 * NotificationAdapter — interface for all notification delivery channels.
 *
 * CONSTRAINT: Every notification channel (email, SMS, webhook, in-app, push, etc.)
 * MUST implement this interface and be registered with the NotificationService
 * via registerAdapter() before it can deliver notifications.
 *
 * Implementation rules:
 * 1. Each adapter handles exactly ONE notification channel.
 * 2. The send() method MUST NOT throw exceptions. Return NotificationResult
 *    with success=false and an error message instead. This ensures that one
 *    failing adapter does not prevent other adapters from sending.
 * 3. The channel property MUST be readonly and match a NotificationChannel type.
 * 4. Adapters should be stateless where possible. Configuration (API keys,
 *    SMTP settings, etc.) should be injected via constructor.
 *
 * Example implementation:
 * ```typescript
 * export class SmsNotificationAdapter implements NotificationAdapter {
 *   readonly channel = 'sms' as const;
 *
 *   constructor(private smsClient: SmsClient) {}
 *
 *   async send(payload: NotificationPayload): Promise<NotificationResult> {
 *     try {
 *       await this.smsClient.send(payload.recipient, payload.body);
 *       return {
 *         success: true,
 *         notificationId: payload.id,
 *         channel: this.channel,
 *         sentAt: new Date(),
 *       };
 *     } catch (err) {
 *       return {
 *         success: false,
 *         notificationId: payload.id,
 *         channel: this.channel,
 *         error: err instanceof Error ? err.message : 'Unknown error',
 *       };
 *     }
 *   }
 * }
 * ```
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

/**
 * Interface that all notification delivery adapters must implement.
 */
export interface NotificationAdapter {
  /** The notification channel this adapter handles (e.g., 'email', 'sms'). */
  readonly channel: NotificationChannel;

  /**
   * Send a notification via this adapter's channel.
   *
   * @param payload - The notification payload to deliver.
   * @returns A result indicating success or failure. Must never throw.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * Current implementation: STUB. Logs email sends instead of delivering them.
 * The interface is production-ready; swap the send() implementation when
 * integrating a real email provider (SendGrid, SES, SMTP, etc.).
 *
 * Configuration can be injected via constructor for real implementations:
 * ```typescript
 * const emailAdapter = new EmailNotificationAdapter({
 *   smtpHost: 'smtp.example.com',
 *   smtpPort: 587,
 *   fromAddress: 'noreply@taskflow.io',
 * });
 * ```
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 * Extend this when integrating a real email provider.
 */
export interface EmailAdapterConfig {
  /** Sender email address */
  fromAddress: string;
  /** SMTP host (for SMTP-based providers) */
  smtpHost?: string;
  /** SMTP port */
  smtpPort?: number;
}

/** Default configuration used when none is provided. */
const defaultEmailConfig: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflow.io',
};

/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'email' channel.
 * Currently a stub that logs delivery attempts. Replace send() internals
 * with a real email client for production use.
 */
export class EmailNotificationAdapter implements NotificationAdapter {
  /** This adapter handles the 'email' channel. */
  readonly channel = 'email' as const;

  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;

  /** Track sent payloads for testing and debugging. */
  private sentPayloads: NotificationPayload[] = [];

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.config = { ...defaultEmailConfig, ...config };
  }

  /**
   * Send an email notification.
   *
   * STUB: Logs the email instead of sending it. Returns success.
   * Replace this implementation with a real email client for production.
   *
   * @param payload - The notification payload to deliver via email.
   * @returns A NotificationResult indicating success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      this.logger.info(
        `[STUB] Sending email from=${this.config.fromAddress} to=${payload.recipient} subject="${payload.subject}"`,
      );

      // In production, this is where you'd call the email provider:
      // await this.emailClient.send({
      //   from: this.config.fromAddress,
      //   to: payload.recipient,
      //   subject: payload.subject,
      //   body: payload.body,
      // });

      this.sentPayloads.push(payload);

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        sentAt: new Date(),
      };
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown email delivery error';
      this.logger.error(`Email delivery failed for ${payload.id}: ${errorMessage}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        error: errorMessage,
      };
    }
  }

  /**
   * Get all payloads that were sent through this adapter.
   * Useful for testing and debugging.
   */
  getSentPayloads(): NotificationPayload[] {
    return [...this.sentPayloads];
  }

  /**
   * Clear sent payload history. Useful for testing.
   */
  clearSentPayloads(): void {
    this.sentPayloads = [];
  }
}

/**
 * Event type definitions for the event-driven notification system.
 *
 * This application uses an event bus for decoupled communication between
 * modules. Services emit events when significant actions occur, and
 * interested listeners handle them independently.
 *
 * Event naming convention: '<domain>:<action>' (e.g., 'order:created').
 *
 * To add a new event:
 * 1. Define the event interface below with a unique 'type' literal.
 * 2. Add it to the AppEvent union type.
 * 3. Emit it via EventBus.emit() from the originating service.
 * 4. Subscribe to it via EventBus.on() in any interested service.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { NotificationChannel } from '../models/notification.js';

// ---------------------------------------------------------------------------
// Domain Events — Order
// ---------------------------------------------------------------------------

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
  user: User;
  timestamp: Date;
}

export interface OrderStatusChangedEvent {
  type: 'order:status-changed';
  order: Order;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Domain Events — User
// ---------------------------------------------------------------------------

export interface UserCreatedEvent {
  type: 'user:created';
  user: User;
  timestamp: Date;
}

export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Notification Lifecycle Events
//
// Emitted by the NotificationService to provide observability into the
// notification pipeline. Other services can subscribe to these for
// logging, metrics, retry logic, or user-facing delivery status.
// ---------------------------------------------------------------------------

/**
 * Emitted when a notification has been successfully delivered by an adapter.
 */
export interface NotificationSentEvent {
  type: 'notification:sent';
  notificationId: string;
  channel: NotificationChannel;
  recipient: string;
  timestamp: Date;
}

/**
 * Emitted when an adapter fails to deliver a notification.
 */
export interface NotificationFailedEvent {
  type: 'notification:failed';
  notificationId: string;
  channel: NotificationChannel;
  recipient: string;
  error: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Union type and helpers
// ---------------------------------------------------------------------------

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationSentEvent
  | NotificationFailedEvent;

export type EventType = AppEvent['type'];

/**
 * NotificationService — central hub for the event-driven notification system.
 *
 * ARCHITECTURE: Event-Driven with Pluggable Adapters
 * ===================================================
 *
 * This service is the ONLY component that dispatches notifications to delivery
 * adapters. The flow is:
 *
 *   1. A domain service (UserService, OrderService, etc.) emits an event
 *      via EventBus.emit().
 *   2. NotificationService receives the event via its EventBus subscriptions.
 *   3. The event handler creates a NotificationPayload and calls dispatch().
 *   4. dispatch() looks up the registered adapter for the payload's channel
 *      and calls adapter.send().
 *   5. NotificationService records the result and emits a lifecycle event
 *      (notification:sent or notification:failed).
 *
 * Constraints:
 * - ALL notifications go through EventBus. No direct adapter calls from
 *   business logic.
 * - ALL adapters must implement the NotificationAdapter interface.
 * - ALL adapters must be registered via registerAdapter() before use.
 * - Adapters must NOT throw — they return NotificationResult with
 *   success=false on failure.
 *
 * Extending this service:
 * - To handle a new domain event: add a handler in registerEventHandlers().
 * - To add a new channel: implement NotificationAdapter and register it.
