  }

  // ---------------------------------------------------------------------------
  // Event Handlers
  //
  // Add new domain event handlers here. Each handler transforms a domain event
  // into one or more CreateNotificationInput objects, then calls send().
  // ---------------------------------------------------------------------------

  /**
   * Register all event handlers for domain events.
   *
   * To handle a new event type:
   * 1. Add the event interface in src/events/event-types.ts
   * 2. Add a handler method in this class
   * 3. Subscribe to the event here
   */
  private registerEventHandlers(): void {
