  /**
   * Create and dispatch a notification.
   *
   * This is the primary entry point for the notification pipeline. Event
   * handlers call this method after transforming domain events into
   * notification inputs.
   *
   * @param input - The notification to create and dispatch.
   * @returns The created Notification record.
   */
  async send(input: CreateNotificationInput): Promise<Notification> {
    const notification: Notification = {
      id: generateNotificationId(),
      channel: input.channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      priority: input.priority ?? 'normal',
      status: 'pending',
      metadata: input.metadata,
      createdAt: new Date(),
    };

    this.notifications.push(notification);

    const result = await this.dispatch(notification);
    this.applyResult(notification, result);

    return notification;
  }

  /**
   * Dispatch a notification to the appropriate adapter.
   * If no adapter is registered for the channel, the notification is recorded
   * as sent (in-memory fallback for backward compatibility and testing).
   */
  private async dispatch(notification: Notification): Promise<NotificationResult> {
    const adapter = this.adapters.get(notification.channel);

    if (!adapter) {
      // No adapter registered — use in-memory recording as fallback.
      // This preserves backward compatibility and allows the service to
      // function without adapters during development or testing.
      this.logger.info(
        `No adapter for channel '${notification.channel}', recording in-memory: ${notification.id}`,
      );
      return {
        success: true,
        notificationId: notification.id,
        channel: notification.channel,
        sentAt: new Date(),
      };
    }

    const payload: NotificationPayload = {
      id: notification.id,
      channel: notification.channel,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
      priority: notification.priority,
      metadata: notification.metadata,
      createdAt: notification.createdAt,
    };

    return adapter.send(payload);
  }

  /**
   * Apply an adapter result to the notification record and emit
   * a lifecycle event.
   */
  private applyResult(notification: Notification, result: NotificationResult): void {
    if (result.success) {
      notification.status = 'sent';
      notification.sentAt = result.sentAt ?? new Date();
      this.logger.info(`Notification sent: ${notification.id} to ${notification.recipient}`);

      // Fire-and-forget: emit lifecycle event for observability
      void this.eventBus.emit({
        type: 'notification:sent',
        notificationId: notification.id,
        channel: notification.channel,
        recipient: notification.recipient,
        timestamp: new Date(),
      });
    } else {
      notification.status = 'failed';
      notification.error = result.error;
      this.logger.error(
        `Notification failed: ${notification.id} — ${result.error ?? 'unknown error'}`,
      );

      void this.eventBus.emit({
        type: 'notification:failed',
        notificationId: notification.id,
        channel: notification.channel,
        recipient: notification.recipient,
        error: result.error ?? 'unknown error',
        timestamp: new Date(),
      });
    }
  }

  // ---------------------------------------------------------------------------
  // Query Methods
  // ---------------------------------------------------------------------------

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by channel.
   */
  getNotificationsByChannel(channel: NotificationChannel): Notification[] {
    return this.notifications.filter((n) => n.channel === channel);
  }

  /**
   * Get notifications filtered by status.
   */
  getNotificationsByStatus(status: Notification['status']): Notification[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Get the total count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

