      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should filter by channel', async () => {
      await service.send({
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'body',
      });

      expect(service.getNotificationsByChannel('email')).toHaveLength(1);
      expect(service.getNotificationsByChannel('sms')).toHaveLength(0);
    });

    it('should filter by status', async () => {
      await service.send({
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'body',
      });

      expect(service.getNotificationsByStatus('sent')).toHaveLength(1);
      expect(service.getNotificationsByStatus('failed')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });

  describe('notification properties', () => {
    it('should set default priority to normal', async () => {
      await service.send({
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'body',
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.priority).toBe('normal');
    });

    it('should respect specified priority', async () => {
      await service.send({
        channel: 'email',
