});

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter();
  });

  const createPayload = (overrides?: Partial<NotificationPayload>): NotificationPayload => ({
    id: 'notif-0001',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    priority: 'normal',
    createdAt: new Date(),
    ...overrides,
  });

  it('should have channel set to email', () => {
    expect(adapter.channel).toBe('email');
  });

  it('should return success result on send', async () => {
    const payload = createPayload();
    const result = await adapter.send(payload);

    expect(result.success).toBe(true);
    expect(result.notificationId).toBe('notif-0001');
    expect(result.channel).toBe('email');
    expect(result.sentAt).toBeDefined();
  });

  it('should track sent payloads', async () => {
    const payload1 = createPayload({ id: 'notif-0001' });
    const payload2 = createPayload({ id: 'notif-0002', recipient: 'bob@example.com' });

    await adapter.send(payload1);
    await adapter.send(payload2);

    const sent = adapter.getSentPayloads();
    expect(sent).toHaveLength(2);
    expect(sent[0]?.recipient).toBe('alice@example.com');
    expect(sent[1]?.recipient).toBe('bob@example.com');
  });

  it('should clear sent payloads', async () => {
    await adapter.send(createPayload());
    expect(adapter.getSentPayloads()).toHaveLength(1);

    adapter.clearSentPayloads();
    expect(adapter.getSentPayloads()).toHaveLength(0);
  });

  it('should accept custom configuration', () => {
    const customAdapter = new EmailNotificationAdapter({
      fromAddress: 'custom@example.com',
      smtpHost: 'smtp.custom.com',
      smtpPort: 465,
    });

    expect(customAdapter.channel).toBe('email');
  });

  it('should return defensive copy of sent payloads', async () => {
    await adapter.send(createPayload());

    const sent1 = adapter.getSentPayloads();
    const sent2 = adapter.getSentPayloads();

    expect(sent1).not.toBe(sent2);
    expect(sent1).toEqual(sent2);
  });
});

/**
 * TaskFlow Pro — A task and order management system.
 *
 * Architecture:
 * - Service Layer: UserService, OrderService, NotificationService (business logic)
 * - Repository Layer: UserRepository, OrderRepository (data access via Repository pattern)
 * - Adapter Layer: EmailNotificationAdapter (notification delivery channels)
 * - Utility Layer: Database, Logger, Pagination (infrastructure)
 * - Event System: EventBus with typed events (decoupled communication)
 *
 * Key architectural decisions:
 * 1. Repository pattern for all data access (no direct DB calls from services)
 * 2. Event-driven notifications: services emit domain events via EventBus,
 *    NotificationService subscribes and dispatches through adapters.
 *    ALL inter-service communication uses EventBus exclusively.
 * 3. Pluggable adapter pattern for notification channels (email, SMS, webhook, etc.)
 */

